import { useMemo } from 'react';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig, PriorityLevel } from '../types/appTypes';

export type FilterMode = 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH' | 'CUSTOM';
export type SourceFilter = 'ALL' | 'PROD' | 'LOG';
export type ShiftFilter = 'ALL' | 'DAY' | 'NIGHT';

export interface AnalyticsFilters {
  mode: FilterMode;
  source: SourceFilter;
  shift: ShiftFilter;
  customStart?: string;
  customEnd?: string;
}

export interface WorkerStats {
  id: string;
  name: string;
  index: number; // WPI 0-10
  tasksDone: number;
  pureWorkMinutes: number;
  utilizationPercent: number;
  performanceRatio: number; // Performance (Tempo) %
  avgReactionSeconds: number;
  fullDistMeters: number;
  emptyDistMeters: number;
  logEfficiency: number;
  confidenceRating: number;
  totalRides: number; 
}

export const useAnalyticsEngine = (
  tasks: Task[],
  archivedTasks: Task[],
  systemBreaks: SystemBreak[],
  mapSectors: MapSector[],
  workplaces: DBItem[],
  logisticsOperations: DBItem[],
  systemConfig: SystemConfig,
  filters: AnalyticsFilters,
  resolveName: (username?: string | null) => string
) => {

  const combinedData = useMemo(() => {
    const allTasks = [...tasks, ...archivedTasks];
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayTs = today.getTime();

    return allTasks.filter(task => {
      const referenceTime = task.completedAt || task.createdAt || 0;
      if (!referenceTime) return false;

      let timeMatch = false;
      switch (filters.mode) {
        case 'TODAY': timeMatch = referenceTime >= todayTs; break;
        case 'YESTERDAY': timeMatch = referenceTime >= (todayTs - 86400000) && referenceTime < todayTs; break;
        case 'WEEK': timeMatch = referenceTime >= (todayTs - (today.getDay() || 7 - 1) * 86400000); break;
        case 'MONTH': timeMatch = referenceTime >= new Date(today.getFullYear(), today.getMonth(), 1).getTime(); break;
        case 'CUSTOM':
          if (!filters.customStart || !filters.customEnd) return false;
          const startTs = new Date(filters.customStart).getTime();
          const endTs = new Date(filters.customEnd).getTime() + 86399999;
          timeMatch = referenceTime >= startTs && referenceTime <= endTs;
          break;
        default: timeMatch = true;
      }
      if (!timeMatch) return false;

      if (filters.source === 'PROD' && !task.isProduction && task.isLogistics) return false;
      if (filters.source === 'LOG' && !task.isLogistics) return false;

      if (filters.shift !== 'ALL') {
        const hour = new Date(referenceTime).getHours();
        const isDay = hour >= 6 && hour < 18;
        if (filters.shift === 'DAY' && !isDay) return false;
        if (filters.shift === 'NIGHT' && isDay) return false;
      }

      return true;
    });
  }, [tasks, archivedTasks, filters]);

  const engineResult = useMemo(() => {
    const VZV_SPEED_MPS = (systemConfig.vzvSpeed || 8) / 3.6;
    const SHIFT_MINUTES = 450;

    const workerTaskMap: Record<string, Task[]> = {};
    const hourlyLoad: Record<number, { prod: number, log: number }> = {};
    for (let h = 5; h <= 23; h++) { hourlyLoad[h] = { prod: 0, log: 0 }; }

    const workplaceLoad: Record<string, { load: number, pal: number, req: number }> = {};
    const highRunnerLoad: Record<string, { load: number, pal: number, req: number }> = {};
    const missingPartsMap: Record<string, number> = {};

    let globalRealErrors = 0;
    let globalFalseAlarms = 0;
    let globalAuditedCount = 0;

    // Globálne akumulátory pre vážený Performance Ratio (Target / Actual)
    let globalTotalTargetMin = 0;
    let globalTotalActualMin = 0;

    combinedData.forEach(t => {
      if (t.isDone && t.completedBy) {
        if (!workerTaskMap[t.completedBy]) workerTaskMap[t.completedBy] = [];
        workerTaskMap[t.completedBy].push(t);
      }

      const refTime = t.completedAt || t.createdAt || 0;
      const hour = new Date(refTime).getHours();

      if (hour >= 5 && hour <= 23) {
        const points = (t.quantityUnit === 'pallet' ? parseFloat((t.quantity || '0').replace(',', '.')) : 1) || 1;
        if (t.isLogistics) hourlyLoad[hour].log += points; 
        else hourlyLoad[hour].prod += points;
      }

      if (t.auditResult) {
        globalAuditedCount++;
        if (t.auditResult === 'NOK') globalRealErrors++;
        else globalFalseAlarms++;
      }
      if (t.isMissing && t.partNumber) {
        missingPartsMap[t.partNumber] = (missingPartsMap[t.partNumber] || 0) + 1;
      }
    });

    const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
      let totalBlocked = 0;
      systemBreaks.forEach(br => {
        const overlapStart = Math.max(startTime, br.start);
        const overlapEnd = Math.min(endTime, br.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
      return totalBlocked;
    };

    const workerStats: WorkerStats[] = Object.entries(workerTaskMap).map(([uid, workerTasks]) => {
      const sorted = [...workerTasks].sort((a, b) => (a.completedAt || 0) - (b.completedAt || 0));

      let wFullDist = 0;
      let wEmptyDist = 0;
      let wTransitDist = 0;
      let wExecMs = 0;
      let wTargetMinTotal = 0;
      let wActualMinTotal = 0;
      let wReactMs = 0;
      let wReactCount = 0;
      let wMissingReported = 0;
      let wRealErrors = 0;
      let wRides = 0; 
      const daysWorked = new Set<string>();

      let lastCoords: { x: number, y: number } | null = null;

      sorted.forEach(task => {
        if (task.completedAt) daysWorked.add(new Date(task.completedAt).toLocaleDateString());

        if (!lastCoords) { wRides++; }

        const qtyVal = parseFloat((task.quantity || '1').replace(',', '.'));
        const points = (task.quantityUnit === 'pallet') ? qtyVal : 1;

        // KPI náporu (Points)
        if (task.workplace) {
          if (!workplaceLoad[task.workplace]) workplaceLoad[task.workplace] = { load: 0, pal: 0, req: 0 };
          workplaceLoad[task.workplace].load += points; workplaceLoad[task.workplace].req++;
          if (task.quantityUnit === 'pallet') workplaceLoad[task.workplace].pal += qtyVal;
        }
        if (task.partNumber) {
          if (!highRunnerLoad[task.partNumber]) highRunnerLoad[task.partNumber] = { load: 0, pal: 0, req: 0 };
          highRunnerLoad[task.partNumber].load += points; highRunnerLoad[task.partNumber].req++;
          if (task.quantityUnit === 'pallet') highRunnerLoad[task.partNumber].pal += qtyVal;
        }

        // Výpočet Performance (Tempo) pre úlohu
        if (task.startedAt && task.completedAt) {
          const rawExecMs = task.completedAt - task.startedAt;
          const blockedMs = calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);
          // ActualDuration - minimálne 1 minúta
          const actualMin = Math.max((rawExecMs - blockedMs) / 60000, 1);

          // TargetDuration - vyhľadanie normy v DB
          const norm = task.isLogistics 
            ? (logisticsOperations.find(o => o.value === task.workplace)?.standardTime || 0)
            : (workplaces.find(w => w.value === task.workplace)?.standardTime || 0);

          const targetMin = norm * qtyVal;

          wActualMinTotal += actualMin;
          wTargetMinTotal += targetMin;
          wExecMs += (rawExecMs - blockedMs);

          globalTotalActualMin += actualMin;
          globalTotalTargetMin += targetMin;
        }

        // Logistika (Prejazdy)
        let oneWayD = 0;
        if (task.isLogistics) {
          const logOp = logisticsOperations.find(o => o.value === task.workplace);
          if (logOp?.distancePx) {
            oneWayD = logOp.distancePx;
            const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
            const possibleTrips = Math.round(((durationMs / 1000) * VZV_SPEED_MPS) / (2 * oneWayD));
            const maxQty = Math.max(1, Math.floor(qtyVal));
            const validatedTrips = Math.min(maxQty, Math.max(1, possibleTrips));
            wFullDist += validatedTrips * oneWayD;
            wEmptyDist += (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);
            wRides += (validatedTrips * 2 - 1); 
            lastCoords = null;
          }
        } 
        else if (task.pickedFromSectorId && task.workplace) {
          const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
          const wp = workplaces.find(w => w.value === task.workplace);
          if (sector && wp) {
            const pickup = { x: sector.coordX, y: sector.coordY };
            const dropoff = { x: wp.coordX || 0, y: wp.coordY || 0 };
            oneWayD = Math.sqrt(Math.pow(dropoff.x - pickup.x, 2) + Math.pow(dropoff.y - pickup.y, 2)) / 10;
            if (lastCoords) {
              wTransitDist += Math.sqrt(Math.pow(pickup.x - lastCoords.x, 2) + Math.pow(pickup.y - lastCoords.y, 2)) / 10;
              wRides++; 
            }
            const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
            const possibleTrips = Math.round(((durationMs / 1000) * VZV_SPEED_MPS) / (2 * oneWayD));
            const maxQty = Math.max(1, Math.floor(qtyVal));
            const validatedTrips = Math.min(maxQty, Math.max(1, possibleTrips));
            if (validatedTrips > 0) {
              wFullDist += validatedTrips * oneWayD;
              wEmptyDist += (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);
              wRides += (validatedTrips * 2 - 1);
            }
            lastCoords = dropoff;
          }
        }

        if (task.createdAt && task.startedAt) {
          const react = task.startedAt - task.createdAt;
          if (react > 0) { wReactMs += react; wReactCount++; }
        }
        if (task.isMissing) {
          wMissingReported++;
          if (task.auditResult === 'NOK') wRealErrors++;
        }
      });

      const nDays = Math.max(daysWorked.size, 1);
      const pureMin = wExecMs / 60000;
      const utilization = (pureMin * 1.15 / (nDays * SHIFT_MINUTES)) * 100;

      // FINAL PERFORMANCE (TEMPO) pre pracovníka - s limitom 200%
      const perf = wActualMinTotal > 0 ? Math.min((wTargetMinTotal / wActualMinTotal) * 100, 200) : 0;

      const reactSec = wReactCount > 0 ? (wReactMs / wReactCount) / 1000 : 0;
      const conf = wMissingReported > 0 ? ((wMissingReported - wRealErrors) / wMissingReported) * 100 : 100;
      const totalEmpty = wEmptyDist + wTransitDist;
      const logEff = (wFullDist + totalEmpty) > 0 ? (wFullDist / (wFullDist + totalEmpty)) * 100 : 50;

      // WPI SCORE
      const sQual = (conf / 100) * 3.0;
      const sUtil = (Math.min(utilization, 100) / 100) * 2.5;
      const sStd = Math.min(perf, 200) / 200 * 2.0;
      const sReac = reactSec > 0 ? (reactSec < 60 ? 1.0 : reactSec < 180 ? 0.5 : 0) : 0.5;
      const sLog = (logEff / 100) * 1.0;
      const wpi = parseFloat((sQual + sUtil + sStd + sReac + sLog).toFixed(1));

      return {
        id: uid, name: resolveName(uid), index: wpi,
        tasksDone: workerTasks.length, pureWorkMinutes: pureMin,
        utilizationPercent: utilization, performanceRatio: perf,
        avgReactionSeconds: reactSec, fullDistMeters: wFullDist,
        emptyDistMeters: totalEmpty, logEfficiency: logEff, confidenceRating: conf,
        totalRides: wRides
      };
    });

    const totalFull = workerStats.reduce((a, b) => a + b.fullDistMeters, 0);
    const totalEmpty = workerStats.reduce((a, b) => a + b.emptyDistMeters, 0);
    const totalPhysicalRides = workerStats.reduce((a, b) => a + b.totalRides, 0);

    // Globálny Performance Ratio (Vážený priemer) - s limitom 200%
    const globalPerformanceRatio = globalTotalActualMin > 0 
        ? Math.min((globalTotalTargetMin / globalTotalActualMin) * 100, 200) 
        : 0;

    return {
      filteredTasks: combinedData,
      globalStats: {
        totalTasks: combinedData.length,
        totalDone: combinedData.filter(t => t.isDone).length,
        totalFullDist: totalFull,
        totalEmptyDist: totalEmpty,
        globalEfficiency: (totalFull + totalEmpty) > 0 ? (totalFull / (totalFull + totalEmpty)) * 100 : 0,
        globalPerformanceRatio: globalPerformanceRatio,
        totalVolume: combinedData.reduce((a, b) => a + (parseFloat((b.quantity || '0').replace(',', '.')) || 0), 0),
        totalPhysicalRides: totalPhysicalRides
      },
      workerStats,
      charts: {
        hourly: Object.entries(hourlyLoad).map(([h, d]) => ({ 
          hour: parseInt(h), 
          label: `${h}h`, 
          production: d.prod, 
          logistics: d.log 
        })).sort((a,b) => a.hour - b.hour),
        highRunners: Object.entries(highRunnerLoad).map(([k, v]) => ({ partNumber: k, ...v, totalTasks: v.req, taskRequests: v.req })).sort((a,b) => b.load - a.load).slice(0, 3),
        workplaces: Object.entries(workplaceLoad).map(([k, v]) => ({ workplace: k, ...v, totalTasks: v.req, taskRequests: v.req })).sort((a,b) => b.load - a.load).slice(0, 3)
      },
      qualityStats: {
        realErrorsCount: globalRealErrors,
        falseAlarmsCount: globalFalseAlarms,
        totalAuditedMissing: globalAuditedCount,
        topMissingParts: Object.entries(missingPartsMap).map(([p, c]) => ({ partNumber: p, count: c })).sort((a,b) => b.count - a.count).slice(0, 3)
      }
    };
  }, [combinedData, systemBreaks, mapSectors, workplaces, logisticsOperations, systemConfig, resolveName]);

  return engineResult;
};

import { useState, useEffect, useRef, useCallback } from 'react';
import { db } from '../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  where,
  limit,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  getDoc,
  arrayUnion,
  writeBatch,
  getDocs
} from 'firebase/firestore';
import { Task, UserData, DBItem, MapSector, PartRequest, BOMRequest, BreakSchedule, SystemBreak, Role, Permission, Notification, PriorityLevel } from '../types/appTypes';
import { PRIORITY_ORDER } from '../constants/uiConstants';

const getISOWeekId = () => {
  const date = new Date();
  date.setHours(0, 0, 0, 0);
  date.setDate(date.getDate() + 3 - (date.getDay() + 6) % 7);
  const week1 = new Date(date.getFullYear(), 0, 4);
  const weekNumber = 1 + Math.round(((date.getTime() - week1.getTime()) / 86400000 - 3 + (week1.getDay() + 6) % 7) / 7);
  return `SANON_${date.getFullYear()}_${weekNumber.toString().padStart(2, '0')}`;
};

export const useFirestoreData = (isAuthenticated: boolean, currentUserRole: string) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [users, setUsers] = useState<UserData[]>([]);
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, any>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]); 
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [draftTasks, setDraftTasks] = useState<Task[]>([]);

  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  const checkPermissionRef = useCallback((permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN') return true;
      const r = rolesRef.current.find(ro => ro.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  }, []);

  const checkBreakStatus = useCallback(() => {
      const now = new Date();
      const currentHHMM = now.getHours().toString().padStart(2, '0') + ':' + 
                          now.getMinutes().toString().padStart(2, '0');
      const isScheduledActive = (breakSchedules || []).some(b => 
          currentHHMM >= b.startTime && currentHHMM <= b.endTime
      );
      const isManualActive = (systemBreaks || []).some(b => b.isActive);
      setIsBreakActive(isScheduledActive || isManualActive);
  }, [breakSchedules, systemBreaks]);

  useEffect(() => {
      checkBreakStatus(); 
      const interval = setInterval(checkBreakStatus, 30000); 
      return () => clearInterval(interval);
  }, [checkBreakStatus]);

  useEffect(() => {
    if (!isAuthenticated) return;
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const aManBlocked = a.isManualBlocked ? 1 : 0;
        const bManBlocked = b.isManualBlocked ? 1 : 0;
        if (aManBlocked !== bManBlocked) return aManBlocked - bManBlocked;
        const pA = PRIORITY_ORDER[a.priority || 'NORMAL'];
        const pB = PRIORITY_ORDER[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });
      setTasks(sortedTasks);
    });
  }, [isAuthenticated, checkPermissionRef]);

  useEffect(() => { 
      const unsubUsers = onSnapshot(collection(db, 'users'), s => setUsers(s.docs.map(d => ({id:d.id, ...d.data()} as UserData))));
      const unsubRoles = onSnapshot(collection(db, 'roles'), s => setRoles(s.docs.map(d => ({id:d.id, ...d.data()} as Role))));
      const unsubPerms = onSnapshot(collection(db, 'permissions'), s => setPermissions(s.docs.map(d => ({id:d.id, ...d.data()} as Permission))));
      const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
      const unsubReasons = onSnapshot(query(collection(db, 'missing_reasons'), orderBy('value')), s => setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem))));
      const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
          const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
          setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
      });
      const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
      const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
      const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));
      const unsubSysBreaks = onSnapshot(collection(db, 'system_breaks'), s => setSystemBreaks(s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak))));
      const unsubNotifications = onSnapshot(collection(db, 'notifications'), s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification))));

      return () => { 
        unsubUsers(); unsubRoles(); unsubPerms(); unsubWp(); unsubReasons(); 
        unsubSectors(); unsubLogOps(); unsubPartReq(); unsubBomReq(); unsubSysBreaks();
        unsubNotifications();
      };
  }, []);

  useEffect(() => {
    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (docSnap) => {
        const cleanMap: Record<string, string> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.value) cleanMap[item.value] = item.description || '';
                });
            }
        }
        setPartsMap(cleanMap);
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (docSnap) => {
        const cleanMap: Record<string, any[]> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.parent && item.child) {
                        if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                        cleanMap[item.parent].push({ child: item.child, consumption: item.consumption || 0 });
                    }
                });
            }
        }
        setBomMap(cleanMap);
    });

    const unsubBreaks = onSnapshot(doc(db, 'settings', 'breaks'), (s) => {
      if (s.exists()) setBreakSchedules(s.data().data || []);
    });

    const unsubDraft = onSnapshot(doc(db, 'settings', 'draft'), (s) => {
      if (s.exists()) setDraftTasks(s.data().data || []);
    });

    return () => { unsubParts(); unsubBOM(); unsubBreaks(); unsubDraft(); };
  }, []);

  const onAddTask = async (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics: boolean = false, note: string = '', isProduction: boolean = false) => {
    const createdBy = localStorage.getItem('app_user') || 'Unknown';
    const newTask = {
        text: partNumber, partNumber, workplace: workplace || '', quantity: quantity || '0', quantityUnit: quantityUnit || 'pcs', priority, isLogistics, isProduction, note, isDone: false, isMissing: false, createdAt: Date.now(), createdBy, status: 'open'
    };
    try { await addDoc(collection(db, 'tasks'), newTask); } catch (e) { console.error("Error adding task", e); }
  };

  const onUpdateTask = async (id: string, updates: Partial<Task>) => {
    try { await updateDoc(doc(db, 'tasks', id), updates); } catch(e) { console.error("Error updating task", e); }
  };

  const onDeleteTask = async (id: string) => {
    try { await deleteDoc(doc(db, 'tasks', id)); } catch(e) { console.error(e); }
  };

  const onToggleTask = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if(!task) return;
    const currentUser = localStorage.getItem('app_user') || 'Unknown';
    const updates: any = { isDone: !task.isDone };
    if (!task.isDone) { updates.completedAt = Date.now(); updates.completedBy = currentUser; updates.status = 'completed'; }
    else { updates.completedAt = null; updates.completedBy = null; updates.status = 'open'; }
    await onUpdateTask(id, updates);
  };

  const onEditTask = async (id: string, newText: string, newPriority?: PriorityLevel) => {
    const updates: any = { text: newText, partNumber: newText };
    if (newPriority) updates.priority = newPriority;
    await onUpdateTask(id, updates);
  };

  const onToggleMissing = async (id: string, reason?: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    const updates: any = { isMissing: !task.isMissing };
    if (!task.isMissing) { updates.missingReason = reason || 'Unknown'; updates.missingReportedBy = user; }
    else { updates.missingReason = null; updates.missingReportedBy = null; }
    await onUpdateTask(id, updates);
  };

  const onSetInProgress = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    if (task.isInProgress) await onUpdateTask(id, { isInProgress: false, inProgressBy: null });
    else await onUpdateTask(id, { isInProgress: true, inProgressBy: user, startedAt: Date.now() });
  };

  const onToggleBlock = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    const user = localStorage.getItem('app_user') || 'Unknown';
    if (task.isBlocked) await onUpdateTask(id, { isBlocked: false, blockedBy: null });
    else await onUpdateTask(id, { isBlocked: true, blockedBy: user });
  };

  const onToggleManualBlock = async (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;
    await onUpdateTask(id, { isManualBlocked: !task.isManualBlocked });
  };

  const onExhaustSearch = async (id: string) => {
    await onUpdateTask(id, { searchExhausted: true });
  };

  const onMarkAsIncorrect = async (id: string) => {
    const user = localStorage.getItem('app_user') || 'Unknown';
    await onUpdateTask(id, { status: 'incorrectly_entered', isDone: true, completedBy: user, completedAt: Date.now() });
  };

  const onAddNote = async (id: string, note: string) => {
    await onUpdateTask(id, { note });
  };

  const onReleaseTask = async (id: string) => {
    await onUpdateTask(id, { isBlocked: false, isManualBlocked: false, isInProgress: false, inProgressBy: null, blockedBy: null });
  };

  const onRequestPart = async (part: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'part_requests'), { partNumber: part, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };

  const onRequestBOM = async (parent: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'bom_requests'), { parentPart: parent, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };

  const onAddNotification = async (notification: Partial<Notification>) => {
    try { await addDoc(collection(db, 'notifications'), { ...notification, timestamp: Date.now() }); }
    catch (e) { console.error("Error adding notification", e); }
  };

  const onClearNotification = async (id: string) => {
    try { await deleteDoc(doc(db, 'notifications', id)); } catch (e) { console.error("Error clearing notification", e); }
  };

  const onUpdatePermission = async (permissionName: string, roleName: string, hasPermission: boolean) => {
    const role = roles.find(r => r.name === roleName);
    if (!role) return;
    try {
        if (hasPermission) { await addDoc(collection(db, 'permissions'), { roleId: role.id, permissionName: permissionName }); } 
        else {
            const q = query(collection(db, 'permissions'), where('roleId', '==', role.id), where('permissionName', '==', permissionName));
            const snap = await getDocs(q);
            const batch = writeBatch(db);
            snap.forEach(d => batch.delete(d.ref));
            await batch.commit();
        }
    } catch (e) { console.error("Error updating permission", e); }
  };

  const onAddRole = async (name: string, parentId?: string, rank: number = 5) => {
    try { await addDoc(collection(db, 'roles'), { name: name.toUpperCase(), parentId: parentId || null, rank: rank, isSystem: false }); } catch (e) { console.error(e); }
  };

  const onDeleteRole = async (id: string) => {
    try {
        await deleteDoc(doc(db, 'roles', id));
        const q = query(collection(db, 'permissions'), where('roleId', '==', id));
        const snap = await getDocs(q);
        const batch = writeBatch(db);
        snap.forEach(d => batch.delete(d.ref));
        await batch.commit();
    } catch (e) { console.error(e); }
  };

  const onAddPart = async (value: string, description: string = '') => {
      try {
          const newItem = { id: `part_${Date.now()}_${Math.random().toString(36).substr(2,9)}`, value: value.toUpperCase(), description, createdAt: Date.now() };
          await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };

  const onBatchAddParts = async (vals: string[]) => {
    try {
      const itemsToAdd: any[] = [];
      vals.forEach((valLine) => {
        if (!valLine.trim()) return;
        const [p, d] = valLine.split(';');
        if(p) { itemsToAdd.push({ id: `part_${Date.now()}_${Math.random().toString(36).substr(2,9)}_${itemsToAdd.length}`, value: p.trim().toUpperCase(), description: d ? d.trim() : '', createdAt: Date.now() }); }
      });
      if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
    } catch (error) { console.error("Error batch adding parts:", error); throw error; }
  };

  const onDeletePart = async (val: string) => {
      try {
          const ref = doc(db, 'settings', 'parts');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => i.value !== val);
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error("Error deleting part:", e); }
  };

  const onDeleteAllParts = async () => {
      try { await setDoc(doc(db, 'settings', 'parts'), { items: [] }); } catch (e) { console.error("Error clearing parts:", e); }
  };

  const onAddWorkplace = async (val: string, time: number = 0, x: number = 0, y: number = 0) => {
      await addDoc(collection(db, 'workplaces'), { value: val, standardTime: time, coordX: x, coordY: y });
  };
  const onUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => {
      await updateDoc(doc(db, 'workplaces', id), updates);
  };
  const onDeleteWorkplace = async (id: string) => {
      await deleteDoc(doc(db, 'workplaces', id));
  };
  const onDeleteAllWorkplaces = async () => {
      const snap = await getDocs(collection(db, 'workplaces'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };
  const onBatchAddWorkplaces = async (vals: string[]) => {
      const batch = writeBatch(db);
      vals.forEach(line => {
          if (!line.trim()) return;
          const [val, time] = line.split(';');
          const ref = doc(collection(db, 'workplaces'));
          batch.set(ref, { value: val.trim(), standardTime: parseInt(time) || 0 });
      });
      await batch.commit();
  };

  const onAddMissingReason = async (val: string) => { await addDoc(collection(db, 'missing_reasons'), { value: val }); };
  const onDeleteMissingReason = async (id: string) => { await deleteDoc(doc(db, 'missing_reasons', id)); };
  const onAddLogisticsOperation = async (val: string, time: number = 0, dist: number = 0) => { await addDoc(collection(db, 'logistics_operations'), { value: val, standardTime: time, distancePx: dist }); };
  const onUpdateLogisticsOperation = async (id: string, updates: Partial<DBItem>) => { await updateDoc(doc(db, 'logistics_operations', id), updates); };
  const onDeleteLogisticsOperation = async (id: string) => { await deleteDoc(doc(db, 'logistics_operations', id)); };
  const onAddUser = async (user: UserData) => { await addDoc(collection(db, 'users'), user); };
  const onUpdatePassword = async (username: string, newPass: string) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { password: newPass }));
  };
  const onUpdateNickname = async (username: string, newNick: string) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { nickname: newNick }));
  };
  const onUpdateUserRole = async (username: string, newRole: string) => {
    if (username.toUpperCase() === 'ADMIN') return;
    try {
        const q = query(collection(db, 'users'), where('username', '==', username));
        const snap = await getDocs(q);
        const batch = writeBatch(db);
        snap.forEach(d => batch.update(d.ref, { role: newRole }));
        await batch.commit();
    } catch (e) { console.error("Error updating user role", e); }
  };
  const onUpdateExportPermission = async (username: string, canExport: boolean) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => updateDoc(d.ref, { canExportAnalytics: canExport }));
  };
  const onDeleteUser = async (username: string) => {
      const q = query(collection(db, 'users'), where('username', '==', username));
      const snap = await getDocs(q);
      snap.forEach(d => deleteDoc(d.ref));
  };
  const onAddMapSector = async (name: string, x: number, y: number, color?: string) => { await addDoc(collection(db, 'map_sectors'), { name, coordX: x, coordY: y, color }); };
  const onUpdateMapSector = async (id: string, updates: Partial<MapSector>) => { await updateDoc(doc(db, 'map_sectors', id), updates); };
  const onDeleteMapSector = async (id: string) => { await deleteDoc(doc(db, 'map_sectors', id)); };

  const onAddBOMItem = async (parent: string, child: string, qty: number) => {
      try {
          const newItem = { id: `bom_${Date.now()}_${Math.random().toString(36).substr(2,9)}`, parent: parent.toUpperCase(), child: child.toUpperCase(), consumption: qty, createdAt: Date.now() };
          await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddBOMItems = async (vals: string[]) => {
      try {
          const itemsToAdd: any[] = [];
          vals.forEach(line => {
              if (!line.trim()) return;
              const [p, c, q] = line.split(';');
              if (p && c) { itemsToAdd.push({ id: `bom_${Date.now()}_${Math.random().toString(36).substr(2,9)}_${itemsToAdd.length}`, parent: p.trim().toUpperCase(), child: c.trim().toUpperCase(), consumption: parseFloat(q?.replace(',', '.') || '0'), createdAt: Date.now() }); }
          });
          if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
      } catch (e) { console.error(e); }
  };
  const onDeleteBOMItem = async (parent: string, child: string) => {
      try {
          const ref = doc(db, 'settings', 'bom');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => !(i.parent === parent && i.child === child));
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error(e); }
  };
  const onDeleteAllBOMItems = async () => { try { await setDoc(doc(db, 'settings', 'bom'), { items: [] }); } catch (e) { console.error(e); } };

  const onDailyClosing = async () => {
    try {
      const tasksRef = collection(db, 'tasks');
      const q = query(tasksRef, where('isDone', '==', true));
      const snapshot = await getDocs(q);
      if (snapshot.empty) return { success: true, count: 0 };
      const completedTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      const draftRef = doc(db, 'settings', 'draft');
      const draftSnap = await getDoc(draftRef);
      let existingData = [];
      if (draftSnap.exists()) existingData = draftSnap.data().data || [];
      const mergedData = [...existingData, ...completedTasks];
      const batch = writeBatch(db);
      batch.set(draftRef, { data: mergedData }, { merge: true });
      snapshot.docs.forEach((doc) => { batch.delete(doc.ref); });
      await batch.commit();
      return { success: true, count: completedTasks.length };
    } catch (e) { console.error("Daily closing failed:", e); return { success: false, count: 0 }; }
  };

  const onWeeklyClosing = async () => {
    try {
        const sanonId = getISOWeekId();
        const draftRef = doc(db, 'settings', 'draft');
        const draftSnap = await getDoc(draftRef);
        let draftTasksFromDb = [];
        if (draftSnap.exists()) draftTasksFromDb = draftSnap.data().data || [];
        const tasksRef = collection(db, 'tasks');
        const q = query(tasksRef, where('isDone', '==', true));
        const activeSnap = await getDocs(q);
        const activeTasks = activeSnap.docs.map(doc => ({ id: doc.id, ...doc.data() }));
        const allTasksToArchive = [...draftTasksFromDb, ...activeTasks];
        if (allTasksToArchive.length === 0) return { success: true, count: 0, sanon: sanonId };
        let batch = writeBatch(db);
        let opCount = 0;
        const sanonRef = doc(db, 'sanony', sanonId);
        batch.set(sanonRef, { tasks: allTasksToArchive, createdAt: Date.now(), id: sanonId });
        opCount++;
        batch.set(draftRef, { data: [] });
        opCount++;
        const docsToDelete = activeSnap.docs;
        for (let i = 0; i < docsToDelete.length; i++) {
            batch.delete(docsToDelete[i].ref);
            opCount++;
            if (opCount >= 498) { await batch.commit(); batch = writeBatch(db); opCount = 0; }
        }
        if (opCount > 0) await batch.commit();
        return { success: true, count: allTasksToArchive.length, sanon: sanonId };
    } catch (e) { console.error("Weekly closing failed:", e); return { success: false, count: 0, sanon: '' }; }
  };

  const fetchSanons = async () => {
      try {
          const snap = await getDocs(collection(db, 'sanony'));
          return snap.docs.map(d => ({ id: d.id, ...d.data() }));
      } catch (e) { console.error("Error fetching sanons", e); return []; }
  };

  return {
    tasks, users, partsMap, bomMap, workplaces, missingReasons, logisticsOperations,
    mapSectors, partRequests, bomRequests, breakSchedules, systemBreaks, isBreakActive,
    roles, permissions, notifications, draftTasks, onClearNotification,
    onAddTask, onUpdateTask, onDeleteTask, onToggleTask, onEditTask, onToggleMissing,
    onSetInProgress, onToggleBlock, onToggleManualBlock, onExhaustSearch, 
    onMarkAsIncorrect, onAddNote, onReleaseTask, onRequestPart, onRequestBOM,
    onAddNotification,
    onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
    onAddWorkplace, onUpdateWorkplace, onDeleteWorkplace, onDeleteAllWorkplaces, onBatchAddWorkplaces,
    onAddMissingReason, onDeleteMissingReason,
    onAddLogisticsOperation, onUpdateLogisticsOperation, onDeleteLogisticsOperation,
    onAddMapSector, onUpdateMapSector, onDeleteMapSector,
    onAddUser, onUpdatePassword, onUpdateNickname, onUpdateUserRole, onUpdateExportPermission, onDeleteUser,
    onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems,
    onUpdatePermission, onAddRole, onDeleteRole,
    onDailyClosing, onWeeklyClosing, fetchSanons
  };
};

import React from 'react';
import PartSearchScreen from './components/PartSearchScreen';
import { useData } from './context/DataContext';
import { SystemConfig, PriorityLevel } from './types/appTypes';
import { db } from './firebase';
import { collection, addDoc } from 'firebase/firestore';

interface AppAuthenticatedProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  installPrompt: any;
  onInstallApp: () => void;
}

const AppAuthenticated: React.FC<AppAuthenticatedProps> = (props) => {
  const data = useData();

  if (!data || !data.tasks || !data.users) {
      return (
          <div className="w-full h-full flex items-center justify-center bg-gray-900">
              <p className="text-white text-xl font-bold animate-pulse">Načítavam systém...</p>
          </div>
      );
  }

  const partsList = data.partsMap 
    ? Object.entries(data.partsMap).map(([p, d]) => ({ id: p, value: p, description: d }))
    : [];

  const safeGetDocCount = (data as any).onGetDocCount || (async () => 0);
  const safePurgeOldTasks = (data as any).onPurgeOldTasks || (async () => 0);
  const safeExportTasksJSON = (data as any).onExportTasksJSON || (async () => {});
  const safeFetchArchivedTasks = (data as any).onFetchArchivedTasks || (async () => []);
  const safeVerifyAdminPassword = (data as any).onVerifyAdminPassword || ((p: string) => false);
  const safeRequestPart = (data as any).onRequestPart || (async () => false);
  const safeRequestBOM = (data as any).onRequestBOM || (async () => false);
  const safeOnDailyClosing = (data as any).onDailyClosing || (async () => ({ success: false, count: 0 }));
  const safeOnWeeklyClosing = (data as any).onWeeklyClosing || (async () => ({ success: false, count: 0, sanon: '' }));
  const safeFetchSanons = (data as any).fetchSanons || (async () => []);

  const handleCreateInventoryTask = async (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics: boolean = false, noteOrPlate: string = '', isProduction: boolean = false) => {
      if (partNumber === "Počítanie zásob") {
          try {
              await addDoc(collection(db, 'tasks'), {
                  partNumber, workplace: workplace || '', quantity: quantity || '0', quantityUnit: quantityUnit || 'pcs', priority, isLogistics, note: noteOrPlate, text: partNumber, status: 'unpacked', isInProgress: true, inProgressBy: props.currentUser, isDone: false, isMissing: false, createdAt: Date.now(), createdBy: props.currentUser, isProduction: !!isProduction
              });
          } catch (e) { console.error("Failed to create inventory task", e); }
      } else {
          try {
              const newTask: any = {
                  text: partNumber, partNumber, workplace: workplace || '', quantity: quantity || '0', quantityUnit: quantityUnit || 'pcs', priority, isLogistics, isProduction, note: isLogistics ? '' : noteOrPlate, plate: isLogistics ? noteOrPlate : '', isDone: false, isMissing: false, createdAt: Date.now(), createdBy: props.currentUser, status: 'open'
              };
              await addDoc(collection(db, 'tasks'), newTask);
          } catch (e) { console.error("Error adding task", e); }
      }
  };

  const handleUpdateTask = (id: string, updates: any) => { if (data.onUpdateTask) data.onUpdateTask(id, updates); };
  const handleDeleteTask = (id: string) => { if (data.onDeleteTask) data.onDeleteTask(id); };

  const handleToggleTask = async (id: string) => {
      const task = data.tasks.find(t => t.id === id);
      if (!task) return;
      const updates: any = { isDone: !task.isDone };
      if (task.isDone) { updates.completedAt = null; updates.completedBy = null; updates.status = 'open'; updates.isInProgress = false; updates.inProgressBy = null; }
      else { updates.completedAt = Date.now(); updates.completedBy = props.currentUser; updates.status = 'completed'; }
      await data.onUpdateTask(id, updates);
  };

  const handleToggleManualBlock = async (id: string) => {
    const task = data.tasks.find(t => t.id === id);
    if (!task) return;
    const newBlockedState = !task.isManualBlocked;
    const updates: any = { isManualBlocked: newBlockedState };
    if (newBlockedState) { updates.isInProgress = false; updates.inProgressBy = null; updates.priority = 'LOW'; }
    else { updates.createdAt = Date.now(); }
    await data.onUpdateTask(id, updates);
  };

  const handleMarkAsIncorrect = async (id: string) => {
    await data.onUpdateTask(id, { isDone: true, status: 'incorrectly_entered', completedBy: props.currentUser, completedAt: Date.now(), isInProgress: false, inProgressBy: null });
  };

  const handleStartAudit = async (id: string) => {
     await data.onUpdateTask(id, { isAuditInProgress: true, auditBy: props.currentUser, isInProgress: false, inProgressBy: null });
  };

  const handleFinishAudit = async (id: string, result: 'found' | 'missing', note: string) => {
     const task = data.tasks.find(t => t.id === id);
     if (!task) return;
     const badgeText = result === 'found' ? `AUDIT (OK) - ${note}` : `AUDIT (NOK) - ${note}`;
     const updates: any = { isAuditInProgress: false, auditFinalBadge: badgeText, auditBy: null, auditResult: result === 'found' ? 'OK' : 'NOK', auditNote: note, auditedBy: props.currentUser, auditedAt: Date.now() };
     if (result === 'found') { updates.isMissing = false; }
     else { updates.isDone = true; updates.status = 'audit_error'; updates.completedBy = props.currentUser; updates.completedAt = Date.now(); updates.isInProgress = false; }
     await data.onUpdateTask(id, updates);
     if (data.onAddNotification && task.createdBy) {
         await data.onAddNotification({ partNumber: task.partNumber || 'Unknown', reason: `AUDIT: ${result.toUpperCase()} - ${note}`, reportedBy: props.currentUser, targetUser: task.createdBy, timestamp: Date.now() });
     }
  };

  const handleToggleMissing = async (id: string, reason?: string) => {
      await data.onToggleMissing(id, reason);
      if (reason) {
          await data.onUpdateTask(id, { isInProgress: false, inProgressBy: null });
          if (data.onAddNotification) {
              const task = data.tasks.find(t => t.id === id);
              if (task) { await data.onAddNotification({ partNumber: task.partNumber || 'Unknown', reason: `CHÝBA: ${reason}`, reportedBy: props.currentUser, targetUser: task.createdBy || '', timestamp: Date.now() }); }
          }
      }
  };

  return (
    <div className="w-full h-full">
        <PartSearchScreen
          {...(data as any)}
          onAddTask={handleCreateInventoryTask}
          onUpdateTask={handleUpdateTask}
          onDeleteTask={handleDeleteTask}
          onToggleTask={handleToggleTask}
          onToggleManualBlock={handleToggleManualBlock}
          onMarkAsIncorrect={handleMarkAsIncorrect}
          onStartAudit={handleStartAudit}
          onFinishAudit={handleFinishAudit}
          onToggleMissing={handleToggleMissing}
          onDeleteMissingItem={(id) => handleToggleMissing(id)}
          onGetDocCount={safeGetDocCount}
          onPurgeOldTasks={safePurgeOldTasks}
          onExportTasksJSON={safeExportTasksJSON}
          onFetchArchivedTasks={safeFetchArchivedTasks}
          onVerifyAdminPassword={safeVerifyAdminPassword}
          onRequestPart={safeRequestPart}
          onRequestBOM={safeRequestBOM}
          onDailyClosing={safeOnDailyClosing}
          onWeeklyClosing={safeOnWeeklyClosing}
          fetchSanons={safeFetchSanons}
          settings={{ draft: { data: data.draftTasks || [] } }}
          parts={partsList}
          currentUser={props.currentUser}
          currentUserRole={props.currentUserRole}
          onLogout={props.onLogout}
          systemConfig={props.systemConfig}
          onUpdateSystemConfig={props.onUpdateSystemConfig}
          onUpdateAdminKey={props.onUpdateAdminKey}
          onToggleAdminLock={props.onToggleAdminLock}
          installPrompt={props.installPrompt}
          onInstallApp={props.onInstallApp}
          dbLoadWarning={false}
        />
    </div>
  );
};

export default AppAuthenticated;

import { useState, useEffect, useRef, useCallback } from 'react';
import { db } from '../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  where,
  limit,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  getDoc,
  arrayUnion,
  writeBatch,
  getDocs
} from 'firebase/firestore';
import { Task, UserData, DBItem, MapSector, PartRequest, BOMRequest, BreakSchedule, SystemBreak, Role, Permission, Notification, PriorityLevel } from '../types/appTypes';
import { PRIORITY_ORDER } from '../constants/uiConstants';

const getISOWeekId = () => {
  const date = new Date();
  date.setHours(0, 0, 0, 0);
  date.setDate(date.getDate() + 3 - (date.getDay() + 6) % 7);
  const week1 = new Date(date.getFullYear(), 0, 4);
  const weekNumber = 1 + Math.round(((date.getTime() - week1.getTime()) / 86400000 - 3 + (week1.getDay() + 6) % 7) / 7);
  return `SANON_${date.getFullYear()}_${weekNumber.toString().padStart(2, '0')}`;
};

export const useFirestoreData = (isAuthenticated: boolean, currentUserRole: string) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [users, setUsers] = useState<UserData[]>([]);
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, any>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]); 
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [draftTasks, setDraftTasks] = useState<Task[]>([]);

  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  const checkPermissionRef = useCallback((permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN') return true;
      const r = rolesRef.current.find(ro => ro.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  }, []);

  const checkBreakStatus = useCallback(() => {
      const now = new Date();
      const currentHHMM = now.getHours().toString().padStart(2, '0') + ':' + 
                          now.getMinutes().toString().padStart(2, '0');
      const isScheduledActive = (breakSchedules || []).some(b => 
          currentHHMM >= b.startTime && currentHHMM <= b.endTime
      );
      const isManualActive = (systemBreaks || []).some(b => b.isActive);
      setIsBreakActive(isScheduledActive || isManualActive);
  }, [breakSchedules, systemBreaks]);

  useEffect(() => {
      checkBreakStatus(); 
      const interval = setInterval(checkBreakStatus, 30000); 
      return () => clearInterval(interval);
  }, [checkBreakStatus]);

  useEffect(() => {
    if (!isAuthenticated) return;
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const aManBlocked = a.isManualBlocked ? 1 : 0;
        const bManBlocked = b.isManualBlocked ? 1 : 0;
        if (aManBlocked !== bManBlocked) return aManBlocked - bManBlocked;
        const pA = PRIORITY_ORDER[a.priority || 'NORMAL'];
        const pB = PRIORITY_ORDER[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });
      setTasks(sortedTasks);
    });
  }, [isAuthenticated, checkPermissionRef]);

  useEffect(() => { 
      const unsubUsers = onSnapshot(collection(db, 'users'), s => setUsers(s.docs.map(d => ({id:d.id, ...d.data()} as UserData))));
      const unsubRoles = onSnapshot(collection(db, 'roles'), s => setRoles(s.docs.map(d => ({id:d.id, ...d.data()} as Role))));
      const unsubPerms = onSnapshot(collection(db, 'permissions'), s => setPermissions(s.docs.map(d => ({id:d.id, ...d.data()} as Permission))));
      const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
      const unsubReasons = onSnapshot(query(collection(db, 'missing_reasons'), orderBy('value')), s => setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem))));
      const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
          const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
          setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
      });
      const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
      const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
      const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));
      const unsubSysBreaks = onSnapshot(collection(db, 'system_breaks'), s => setSystemBreaks(s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak))));
      const unsubNotifications = onSnapshot(collection(db, 'notifications'), s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification))));

      return () => { 
        unsubUsers(); unsubRoles(); unsubPerms(); unsubWp(); unsubReasons(); 
        unsubSectors(); unsubLogOps(); unsubPartReq(); unsubBomReq(); unsubSysBreaks();
        unsubNotifications();
      };
  }, []);

  useEffect(() => {
    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (docSnap) => {
        const cleanMap: Record<string, string> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.value) cleanMap[item.value] = item.description || '';
                });
            }
        }
        setPartsMap(cleanMap);
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (docSnap) => {
        const cleanMap: Record<string, any[]> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.parent && item.child) {
                        if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                        cleanMap[item.parent].push({ child: item.child, consumption: item.consumption || 0 });
                    }
                });
            }
        }
        setBomMap(cleanMap);
    });

    const unsubBreaks = onSnapshot(doc(db, 'settings', 'breaks'), (s) => {
