const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
  const { 
    currentUser, currentUserRole, onLogout, tasks, draftTasks, onAddTask, onUpdateTask, roles, permissions,
    notifications, onClearNotification, installPrompt, onInstallApp, parts, workplaces,
    onToggleTask, onEditTask, onDeleteTask, onToggleMissing, onSetInProgress, onToggleManualBlock, onExhaustSearch, onMarkAsIncorrect, onAddNote, onReleaseTask, missingReasons,
    users,
    onApprovePartRequest, onRejectPartRequest,
    onArchiveTasks, onDailyClosing, onWeeklyClosing, fetchSanons,
    breakSchedules,
    bomMap, bomRequests, onApproveBOMRequest, onRejectBOMRequest,
    onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword,
    systemConfig, onUpdateSystemConfig,
    dbLoadWarning, onGetDocCount, onPurgeOldTasks, onExportTasksJSON,
    mapSectors, settings
  } = props;

  const { t, language, setLanguage } = useLanguage();
  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'logistics' | 'permissions' | 'inventory' | 'catalog'>('entry');
  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [entryMode, setEntryMode] = useState<'production' | 'logistics'>('production');

  // STAVY PRE SEKTOR PICKER
  const [pickingTask, setPickingTask] = useState<Task | null>(null);

  const [selectedPart, setSelectedPart] = useState<string | null>(null);
  const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
  const [logisticsRef, setLogisticsRef] = useState('');
  const [logisticsOp, setLogisticsOp] = useState('');
  const [logisticsPlate, setLogisticsPlate] = useState('');
  const [quantity, setQuantity] = useState<string>('');
  const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
  const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);

  const unitLock = useMemo(() => {
    if (entryMode === 'logistics' || !selectedPart) return null;
    const partData = parts.find(p => p.value === selectedPart);
    const desc = partData?.description || '';
    if (desc.includes('S0001S')) return 'pcs';
    if (desc.includes('S0002S')) return 'boxes';
    if (desc.includes('S0003S')) return 'pallet';
    return null;
  }, [selectedPart, entryMode, parts]);

  useEffect(() => { if (unitLock) setQuantityUnit(unitLock); }, [unitLock]);

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = useCallback((permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) return true;
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  }, [currentUserRole, currentRoleId, permissions]);

  const resolveName = useCallback((username?: string | null) => {
      if (!username) return '-';
      const u = users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  }, [users]);

  const logisticsOperationsList = useMemo(() => props.logisticsOperations || [], [props.logisticsOperations]);

  const handleAdd = () => {
    if (entryMode === 'production') {
        if (!selectedPart || !selectedWorkplace || !quantity) { alert(t('fill_all_fields')); return; }
        onAddTask(selectedPart, selectedWorkplace, quantity, quantityUnit, priority, false);
    } else {
        if (!logisticsRef || !logisticsOp || !quantity) { alert(t('fill_all_fields')); return; }
        onAddTask(logisticsRef, logisticsOp, quantity, quantityUnit, priority, true, logisticsPlate);
    }
    setSelectedPart(null); setSelectedWorkplace(null); setLogisticsRef(''); setLogisticsOp(''); setLogisticsPlate(''); setQuantity('');
    setPriority('NORMAL'); setShowSuccessMessage(true); setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  // LOGIKA KONTROLY SEKTORA PRED DOKONČENÍM
  const handleCompleteWithSectorCheck = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task) return;

    // Ak je to výrobná úloha, ide sa dokončiť (isDone je false) a chýba priradený sektor:
    if (!task.isLogistics && !task.isDone && !task.pickedFromSectorId) {
        setPickingTask(task);
        return;
    }
    onToggleTask(id);
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      <AppHeader currentUser={currentUser} currentUserRole={currentUserRole} users={users} onLogout={onLogout} language={language} setLanguage={setLanguage} t={t} isFullscreen={false} onToggleFullscreen={()=>{}} installPrompt={installPrompt} onInstallApp={onInstallApp} hasPermission={hasPermission} resolveName={resolveName} />

      {showSuccessMessage && (
        <div className="fixed top-24 right-6 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce font-black tracking-widest">✓ {t('sent_msg')}</div>
      )}

      <TabNavigator activeTab={activeTab} setActiveTab={setActiveTab} hasPermission={hasPermission} t={t} counts={{ tasks: (tasks || []).filter(t=>!t.isDone).length, pendingRequests: (props.partRequests?.length || 0) + (props.bomRequests?.length || 0) }} />

      <div className="flex-grow overflow-y-auto p-3 md:p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto w-full">
          {activeTab === 'entry' && (
            <ProductionEntry 
                mode={entryMode} setMode={setMode => { setEntryMode(setMode); setQuantityUnit(setMode === 'logistics' ? 'pallet' : 'pcs'); }} 
                selectedPart={selectedPart} setSelectedPart={setSelectedPart} 
                selectedWorkplace={selectedWorkplace} setSelectedWorkplace={setSelectedWorkplace} 
                logisticsRef={logisticsRef} setLogisticsRef={setLogisticsRef} 
                logisticsPlate={logisticsPlate} setLogisticsPlate={setLogisticsPlate} 
                logisticsOp={logisticsOp} setLogisticsOp={setLogisticsOp} 
                quantity={quantity} setQuantity={setQuantity} 
                quantityUnit={quantityUnit} setQuantityUnit={setQuantityUnit} 
                priority={priority} setPriority={setPriority} 
                parts={(parts || []).map(p => p.value)} workplaces={workplaces} 
                logisticsOperationsList={logisticsOperationsList} 
                t={t} language={language} hasPermission={hasPermission} 
                handleAdd={handleAdd} onRequestPart={props.onRequestPart} 
                isUnitLocked={!!unitLock} 
            />
          )}
          {activeTab === 'analytics' && (
            <AnalyticsTab 
              tasks={tasks} 
              draftTasks={draftTasks}
              onFetchArchivedTasks={props.onFetchArchivedTasks} 
              fetchSanons={fetchSanons} 
              settings={settings} 
              systemBreaks={props.systemBreaks} 
              resolveName={resolveName} 
              mapSectors={mapSectors} 
              workplaces={workplaces} 
              systemConfig={systemConfig} 
              logisticsOperations={logisticsOperationsList} 
              users={users} 
              currentUser={currentUser} 
              currentUserRole={currentUserRole} 
              hasPermission={hasPermission} 
            />
          )}
          {activeTab === 'settings' && <SettingsTab hasPermission={hasPermission} currentUserRole={currentUserRole} users={users} onAddUser={props.onAddUser} onUpdatePassword={props.onUpdatePassword} onUpdateNickname={props.onUpdateNickname} onUpdateUserRole={props.onUpdateUserRole} onDeleteUser={props.onDeleteUser} onUpdateExportPermission={props.onUpdateExportPermission} parts={parts} workplaces={workplaces} missingReasons={missingReasons} onAddPart={props.onAddPart} onBatchAddParts={props.onBatchAddParts} onDeletePart={props.onDeletePart} onDeleteAllParts={props.onDeleteAllParts} onAddWorkplace={props.onAddWorkplace} onUpdateWorkplace={props.onUpdateWorkplace} onBatchAddWorkplaces={props.onBatchAddWorkplaces} onDeleteWorkplace={props.onDeleteWorkplace} onDeleteAllWorkplaces={props.onDeleteAllWorkplaces} onAddMissingReason={props.onAddMissingReason} onDeleteMissingReason={props.onDeleteMissingReason} logisticsOperations={logisticsOperationsList} onAddLogisticsOperation={props.onAddLogisticsOperation} onUpdateLogisticsOperation={props.onUpdateLogisticsOperation} onDeleteLogisticsOperation={props.onDeleteLogisticsOperation} mapSectors={mapSectors} onAddMapSector={props.onAddMapSector} onDeleteMapSector={props.onDeleteMapSector} onUpdateMapSector={props.onUpdateMapSector} partRequests={props.partRequests} onApprovePartRequest={onApprovePartRequest} onRejectPartRequest={onRejectPartRequest} onArchiveTasks={onArchiveTasks} onDailyClosing={props.onDailyClosing} onWeeklyClosing={props.onWeeklyClosing} fetchSanons={fetchSanons} breakSchedules={breakSchedules} onAddBreakSchedule={props.onAddBreakSchedule} onDeleteBreakSchedule={props.onDeleteBreakSchedule} bomMap={bomMap} bomRequests={bomRequests} onAddBOMItem={props.onAddBOMItem} onBatchAddBOMItems={props.onBatchAddBOMItems} onDeleteBOMItem={props.onDeleteBOMItem} onDeleteAllBOMItems={props.onDeleteAllBOMItems} onApproveBOMRequest={onApproveBOMRequest} onRejectBOMRequest={onRejectBOMRequest} roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} installPrompt={null} onInstallApp={()=>{}} systemConfig={systemConfig} onUpdateSystemConfig={onUpdateSystemConfig} dbLoadWarning={dbLoadWarning} resolveName={resolveName} onGetDocCount={onGetDocCount} onPurgeOldTasks={onPurgeOldTasks} onExportTasksJSON={onExportTasksJSON} onUpdateAdminKey={props.onUpdateAdminKey} onToggleAdminLock={props.onToggleAdminLock} />}
          {activeTab === 'tasks' && <div className="animate-fade-in pb-20"><div className="mb-6 flex justify-center"><input type="text" value={taskSearchQuery} onChange={e => setTaskSearchQuery(e.target.value)} className="w-full max-w-lg h-12 px-6 bg-gray-800 border border-gray-700 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase" placeholder={t('task_search_placeholder')} /></div><TaskList currentUser={currentUserRole} currentUserName={currentUser} tasks={(tasks || []).filter(t => { const q = taskSearchQuery.toLowerCase(); return (t.partNumber && t.partNumber.toLowerCase().includes(q)) || (t.text && t.text.toLowerCase().includes(q)) || (t.workplace && t.workplace.toLowerCase().includes(q)); })} onToggleTask={handleCompleteWithSectorCheck} onEditTask={onEditTask} onDeleteTask={onDeleteTask} onToggleMissing={onToggleMissing} onSetInProgress={onSetInProgress} onToggleBlock={props.onToggleBlock} onToggleManualBlock={onToggleManualBlock} onExhaustSearch={onExhaustSearch} onMarkAsIncorrect={onMarkAsIncorrect} onAddNote={onAddNote} onReleaseTask={onReleaseTask} onAuditPart={()=>{}} resolveName={resolveName} missingReasons={missingReasons} hasPermission={hasPermission} /></div>}
          {activeTab === 'bom' && <BOMScreen parts={parts} workplaces={workplaces} bomMap={bomMap} onAddTask={onAddTask} onRequestBOM={props.onRequestBOM} t={t} language={language} />}
          {activeTab === 'missing' && <MissingItemsTab tasks={tasks} onDeleteMissingItem={props.onDeleteMissingItem} hasPermission={hasPermission} resolveName={resolveName} />}
          {activeTab === 'inventory' && <InventoryTab currentUser={currentUser} tasks={tasks} onAddTask={onAddTask} onUpdateTask={onUpdateTask} onToggleTask={onToggleTask} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} parts={(parts || []).map(p=>p.value)} onRequestPart={props.onRequestPart} resolveName={resolveName} />}
          {activeTab === 'logistics' && <LogisticsCenterTab tasks={tasks} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} resolveName={resolveName} />}
          {activeTab === 'permissions' && <PermissionsTab roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} onVerifyAdminPassword={onVerifyAdminPassword} />}
          {activeTab === 'catalog' && <PartCatalogTab parts={parts} onSelectPart={p => { setSelectedPart(p.value); setActiveTab('entry'); }} />}
          </div>
      </div>

      {pickingTask && createPortal(
          <SectorPickerModal 
              task={pickingTask}
              mapSectors={props.mapSectors}
              onClose={() => setPickingTask(null)}
              onConfirm={(sectorId) => {
                  onUpdateTask(pickingTask.id, { pickedFromSectorId: sectorId });
                  onToggleTask(pickingTask.id);
                  setPickingTask(null);
              }}
          />,
          document.body
      )}
    </div>
  );
};

