import { useMemo } from 'react';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig, PriorityLevel } from '../types/appTypes';

export type FilterMode = 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH' | 'CUSTOM';
export type SourceFilter = 'ALL' | 'PROD' | 'LOG';
export type ShiftFilter = 'ALL' | 'DAY' | 'NIGHT';

export interface AnalyticsFilters {
  mode: FilterMode;
  source: SourceFilter;
  shift: ShiftFilter;
  customStart?: string;
  customEnd?: string;
}

export interface WorkerStats {
  id: string;
  name: string;
  index: number; // WPI 0-10
  tasksDone: number;
  pureWorkMinutes: number;
  utilizationPercent: number;
  performanceRatio: number; // Performance (Tempo) %
  avgReactionSeconds: number;
  fullDistMeters: number;
  emptyDistMeters: number;
  logEfficiency: number;
  confidenceRating: number;
  totalRides: number; 
}

export const useAnalyticsEngine = (
  tasks: Task[],
  archivedTasks: Task[],
  systemBreaks: SystemBreak[],
  mapSectors: MapSector[],
  workplaces: DBItem[],
  logisticsOperations: DBItem[],
  systemConfig: SystemConfig,
  filters: AnalyticsFilters,
  resolveName: (username?: string | null) => string
) => {

  const combinedData = useMemo(() => {
    const allTasks = [...tasks, ...archivedTasks];
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const todayTs = today.getTime();

    return allTasks.filter(task => {
      const referenceTime = task.completedAt || task.createdAt || 0;
      if (!referenceTime) return false;

      let timeMatch = false;
      switch (filters.mode) {
        case 'TODAY': timeMatch = referenceTime >= todayTs; break;
        case 'YESTERDAY': timeMatch = referenceTime >= (todayTs - 86400000) && referenceTime < todayTs; break;
        case 'WEEK': timeMatch = referenceTime >= (todayTs - (today.getDay() || 7 - 1) * 86400000); break;
        case 'MONTH': timeMatch = referenceTime >= new Date(today.getFullYear(), today.getMonth(), 1).getTime(); break;
        case 'CUSTOM':
          if (!filters.customStart || !filters.customEnd) return false;
          const startTs = new Date(filters.customStart).getTime();
          const endTs = new Date(filters.customEnd).getTime() + 86399999;
          timeMatch = referenceTime >= startTs && referenceTime <= endTs;
          break;
        default: timeMatch = true;
      }
      if (!timeMatch) return false;

      if (filters.source === 'PROD' && !task.isProduction && task.isLogistics) return false;
      if (filters.source === 'LOG' && !task.isLogistics) return false;

      if (filters.shift !== 'ALL') {
        const hour = new Date(referenceTime).getHours();
        const isDay = hour >= 6 && hour < 18;
        if (filters.shift === 'DAY' && !isDay) return false;
        if (filters.shift === 'NIGHT' && isDay) return false;
      }

      return true;
    });
  }, [tasks, archivedTasks, filters]);

  const engineResult = useMemo(() => {
    const VZV_SPEED_MPS = (systemConfig.vzvSpeed || 8) / 3.6;
    const SHIFT_MINUTES = 450;

    const workerTaskMap: Record<string, Task[]> = {};
    const hourlyLoad: Record<number, { prod: number, log: number }> = {};
    for (let h = 5; h <= 23; h++) { hourlyLoad[h] = { prod: 0, log: 0 }; }

    const workplaceLoad: Record<string, { load: number, pal: number, req: number }> = {};
    const highRunnerLoad: Record<string, { load: number, pal: number, req: number }> = {};
    const missingPartsMap: Record<string, number> = {};

    let globalRealErrors = 0;
    let globalFalseAlarms = 0;
    let globalAuditedCount = 0;

    // Globálne akumulátory pre vážený Performance Ratio (Target / Actual)
    let globalTotalTargetMin = 0;
    let globalTotalActualMin = 0;

    combinedData.forEach(t => {
      if (t.isDone && t.completedBy) {
        if (!workerTaskMap[t.completedBy]) workerTaskMap[t.completedBy] = [];
        workerTaskMap[t.completedBy].push(t);
      }

      const refTime = t.completedAt || t.createdAt || 0;
      const hour = new Date(refTime).getHours();

      if (hour >= 5 && hour <= 23) {
        const points = (t.quantityUnit === 'pallet' ? parseFloat((t.quantity || '0').replace(',', '.')) : 1) || 1;
        if (t.isLogistics) hourlyLoad[hour].log += points; 
        else hourlyLoad[hour].prod += points;
      }

      if (t.auditResult) {
        globalAuditedCount++;
        if (t.auditResult === 'NOK') globalRealErrors++;
        else globalFalseAlarms++;
      }
      if (t.isMissing && t.partNumber) {
        missingPartsMap[t.partNumber] = (missingPartsMap[t.partNumber] || 0) + 1;
      }
    });

    const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
      let totalBlocked = 0;
      systemBreaks.forEach(br => {
        const overlapStart = Math.max(startTime, br.start);
        const overlapEnd = Math.min(endTime, br.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
      return totalBlocked;
    };

    const workerStats: WorkerStats[] = Object.entries(workerTaskMap).map(([uid, workerTasks]) => {
      const sorted = [...workerTasks].sort((a, b) => (a.completedAt || 0) - (b.completedAt || 0));

      let wFullDist = 0;
      let wEmptyDist = 0;
      let wTransitDist = 0;
      let wExecMs = 0;
      let wTargetMinTotal = 0;
      let wActualMinTotal = 0;
      let wReactMs = 0;
      let wReactCount = 0;
      let wMissingReported = 0;
      let wRealErrors = 0;
      let wRides = 0; 
      const daysWorked = new Set<string>();

      let lastCoords: { x: number, y: number } | null = null;

      sorted.forEach(task => {
        if (task.completedAt) daysWorked.add(new Date(task.completedAt).toLocaleDateString());

        if (!lastCoords) { wRides++; }

        const qtyVal = parseFloat((task.quantity || '1').replace(',', '.'));
        const points = (task.quantityUnit === 'pallet') ? qtyVal : 1;

        // KPI náporu (Points)
        if (task.workplace) {
          if (!workplaceLoad[task.workplace]) workplaceLoad[task.workplace] = { load: 0, pal: 0, req: 0 };
          workplaceLoad[task.workplace].load += points; workplaceLoad[task.workplace].req++;
          if (task.quantityUnit === 'pallet') workplaceLoad[task.workplace].pal += qtyVal;
        }
        if (task.partNumber) {
          if (!highRunnerLoad[task.partNumber]) highRunnerLoad[task.partNumber] = { load: 0, pal: 0, req: 0 };
          highRunnerLoad[task.partNumber].load += points; highRunnerLoad[task.partNumber].req++;
          if (task.quantityUnit === 'pallet') highRunnerLoad[task.partNumber].pal += qtyVal;
        }

        // Výpočet Performance (Tempo) pre úlohu
        if (task.startedAt && task.completedAt) {
          const rawExecMs = task.completedAt - task.startedAt;
          const blockedMs = calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);

          let actualMin = (rawExecMs - blockedMs) / 60000;

          // TargetDuration - vyhľadanie normy v DB
          const norm = task.isLogistics 
            ? (logisticsOperations.find(o => o.value === task.workplace)?.standardTime || 0)
            : (workplaces.find(w => w.value === task.workplace)?.standardTime || 0);

          const targetMin = norm * qtyVal;

          // --- ANTI-CHEAT LOGIC START ---
          if (actualMin < 0.5) {
              // PUNISHMENT: Ak je úloha hotová pod 30s, rátame ju ako 2x Normu (Výkon bude 50%)
              // Safety: Ak je norma 0, počítame 2 minúty, aby sme predišli nekonečnej efektivite pri rýchlom klikaní
              actualMin = (targetMin * 2) || 2; 
          } else {
              // Štandardná poistka (min 1 minúta pre úlohy nad 30s)
              actualMin = Math.max(actualMin, 1);
          }
          // --- ANTI-CHEAT LOGIC END ---

          wActualMinTotal += actualMin;
          wTargetMinTotal += targetMin;

          // Pre 'wExecMs' (čistý čas práce pre analytiku času) ponecháme reálny čas
          wExecMs += Math.max(rawExecMs - blockedMs, 0);

          globalTotalActualMin += actualMin;
          globalTotalTargetMin += targetMin;
        }

        // Logistika (Prejazdy)
        let oneWayD = 0;
        if (task.isLogistics) {
          const logOp = logisticsOperations.find(o => o.value === task.workplace);
          if (logOp?.distancePx) {
            oneWayD = logOp.distancePx;
            const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
            const possibleTrips = Math.round(((durationMs / 1000) * VZV_SPEED_MPS) / (2 * oneWayD));
            const maxQty = Math.max(1, Math.floor(qtyVal));
            const validatedTrips = Math.min(maxQty, Math.max(1, possibleTrips));
            wFullDist += validatedTrips * oneWayD;
            wEmptyDist += (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);
            wRides += (validatedTrips * 2 - 1); 
            lastCoords = null;
          }
        } 
        else if (task.pickedFromSectorId && task.workplace) {
          const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
          const wp = workplaces.find(w => w.value === task.workplace);
          if (sector && wp) {
            const pickup = { x: sector.coordX, y: sector.coordY };
            const dropoff = { x: wp.coordX || 0, y: wp.coordY || 0 };
            oneWayD = Math.sqrt(Math.pow(dropoff.x - pickup.x, 2) + Math.pow(dropoff.y - pickup.y, 2)) / 10;
            if (lastCoords) {
              wTransitDist += Math.sqrt(Math.pow(pickup.x - lastCoords.x, 2) + Math.pow(pickup.y - lastCoords.y, 2)) / 10;
              wRides++; 
            }
            const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
            const possibleTrips = Math.round(((durationMs / 1000) * VZV_SPEED_MPS) / (2 * oneWayD));
            const maxQty = Math.max(1, Math.floor(qtyVal));
            const validatedTrips = Math.min(maxQty, Math.max(1, possibleTrips));
            if (validatedTrips > 0) {
              wFullDist += validatedTrips * oneWayD;
              wEmptyDist += (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);
              wRides += (validatedTrips * 2 - 1);
            }
            lastCoords = dropoff;
          }
        }

        if (task.createdAt && task.startedAt) {
          const react = task.startedAt - task.createdAt;
          if (react > 0) { wReactMs += react; wReactCount++; }
        }
        if (task.isMissing) {
          wMissingReported++;
          if (task.auditResult === 'NOK') wRealErrors++;
        }
      });

      const nDays = Math.max(daysWorked.size, 1);
      const pureMin = wExecMs / 60000;
      const utilization = (pureMin * 1.15 / (nDays * SHIFT_MINUTES)) * 100;

      // FINAL PERFORMANCE (TEMPO) pre pracovníka - s limitom 200%
      const perf = wActualMinTotal > 0 ? Math.min((wTargetMinTotal / wActualMinTotal) * 100, 200) : 0;

      const reactSec = wReactCount > 0 ? (wReactMs / wReactCount) / 1000 : 0;
      const conf = wMissingReported > 0 ? ((wMissingReported - wRealErrors) / wMissingReported) * 100 : 100;
      const totalEmpty = wEmptyDist + wTransitDist;
      const logEff = (wFullDist + totalEmpty) > 0 ? (wFullDist / (wFullDist + totalEmpty)) * 100 : 50;

      // WPI SCORE
      const sQual = (conf / 100) * 3.0;
      const sUtil = (Math.min(utilization, 100) / 100) * 2.5;
      const sStd = Math.min(perf, 200) / 200 * 2.0;
      const sReac = reactSec > 0 ? (reactSec < 60 ? 1.0 : reactSec < 180 ? 0.5 : 0) : 0.5;
      const sLog = (logEff / 100) * 1.0;
      const wpi = parseFloat((sQual + sUtil + sStd + sReac + sLog).toFixed(1));

      return {
        id: uid, name: resolveName(uid), index: wpi,
        tasksDone: workerTasks.length, pureWorkMinutes: pureMin,
        utilizationPercent: utilization, performanceRatio: perf,
        avgReactionSeconds: reactSec, fullDistMeters: wFullDist,
        emptyDistMeters: totalEmpty, logEfficiency: logEff, confidenceRating: conf,
        totalRides: wRides
      };
    });

    const totalFull = workerStats.reduce((a, b) => a + b.fullDistMeters, 0);
    const totalEmpty = workerStats.reduce((a, b) => a + b.emptyDistMeters, 0);
    const totalPhysicalRides = workerStats.reduce((a, b) => a + b.totalRides, 0);

    // Globálny Performance Ratio (Vážený priemer) - s limitom 200%
    const globalPerformanceRatio = globalTotalActualMin > 0 
        ? Math.min((globalTotalTargetMin / globalTotalActualMin) * 100, 200) 
        : 0;

    return {
      filteredTasks: combinedData,
      globalStats: {
        totalTasks: combinedData.length,
        totalDone: combinedData.filter(t => t.isDone).length,
        totalFullDist: totalFull,
        totalEmptyDist: totalEmpty,
        globalEfficiency: (totalFull + totalEmpty) > 0 ? (totalFull / (totalFull + totalEmpty)) * 100 : 0,
        globalPerformanceRatio: globalPerformanceRatio,
        totalVolume: combinedData.reduce((a, b) => a + (parseFloat((b.quantity || '0').replace(',', '.')) || 0), 0),
        totalPhysicalRides: totalPhysicalRides
      },
      workerStats,
      charts: {
        hourly: Object.entries(hourlyLoad).map(([h, d]) => ({ 
          hour: parseInt(h), 
          label: `${h}h`, 
          production: d.prod, 
          logistics: d.log 
        })).sort((a,b) => a.hour - b.hour),
        highRunners: Object.entries(highRunnerLoad).map(([k, v]) => ({ partNumber: k, ...v, totalTasks: v.req, taskRequests: v.req })).sort((a,b) => b.load - a.load).slice(0, 3),
        workplaces: Object.entries(workplaceLoad).map(([k, v]) => ({ workplace: k, ...v, totalTasks: v.req, taskRequests: v.req })).sort((a,b) => b.load - a.load).slice(0, 3)
      },
      qualityStats: {
        realErrorsCount: globalRealErrors,
        falseAlarmsCount: globalFalseAlarms,
        totalAuditedMissing: globalAuditedCount,
        topMissingParts: Object.entries(missingPartsMap).map(([p, c]) => ({ partNumber: p, count: c })).sort((a,b) => b.count - a.count).slice(0, 3)
      }
    };
  }, [combinedData, systemBreaks, mapSectors, workplaces, logisticsOperations, systemConfig, resolveName]);

  return engineResult;
};

import React, { useMemo } from 'react';
import { createPortal } from 'react-dom';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig } from '../../../types/appTypes';
import { useLanguage } from '../../LanguageContext';

interface WorkerDetailModalProps {
  name: string;
  tasks: Task[];
  periodLabel: string;
  systemBreaks: SystemBreak[];
  onClose: () => void;
  mapSectors: MapSector[];
  workplaces: DBItem[];
  systemConfig: SystemConfig;
  logisticsOperations: DBItem[];
}

const WorkerDetailModal: React.FC<WorkerDetailModalProps> = ({ name, tasks, periodLabel, systemBreaks, onClose, mapSectors, workplaces, systemConfig, logisticsOperations }) => {
  const { t, language } = useLanguage();
  const VZV_SPEED_MPS = (systemConfig.vzvSpeed || 8) / 3.6;

  const calculateBlockedTime = (history: any[] | undefined, startTime: number, endTime: number): number => {
    let totalBlocked = 0;
    if (history && history.length > 0) {
      history.forEach(session => {
        const overlapStart = Math.max(startTime, session.start);
        const overlapEnd = Math.min(endTime, session.end || endTime);
        if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
      });
    }
    systemBreaks.forEach(br => {
      const overlapStart = Math.max(startTime, br.start);
      const overlapEnd = Math.min(endTime, br.end || endTime);
      if (overlapEnd > overlapStart) totalBlocked += (overlapEnd - overlapStart);
    });
    return totalBlocked;
  };

  const stats = useMemo(() => {
    let totalLoad = 0;
    let palCount = 0;
    let pcsTasks = 0;
    let missingReported = 0;
    let realErrors = 0;
    let totalExecMs = 0; // Reálne odpracovaný čas (nezmenený)
    let totalStandardMin = 0;
    let totalReactionMs = 0;
    let reactionCount = 0;
    let durations: number[] = [];

    // Nové akumulátory pre férový výkon s limitom (Capped Average)
    let sumPerformance = 0;
    let countPerformanceTasks = 0;

    let totalFullDist = 0;
    let totalEmptyDist = 0;
    let totalTransitBetweenTasksDist = 0;

    const workplacesMap: Record<string, number> = {};
    const partsMap: Record<string, number> = {};
    const uniqueDaysWorked = new Set<string>();

    const sortedTasks = [...tasks].sort((a,b) => (a.completedAt || 0) - (b.completedAt || 0));
    let lastWorkplaceCoords: { x: number, y: number } | null = null;

    sortedTasks.forEach(task => {
      if (task.completedAt) {
        const dateKey = new Date(task.completedAt).toLocaleDateString('sk-SK');
        uniqueDaysWorked.add(dateKey);
      }

      const qtyVal = parseFloat((task.quantity || '1').replace(',', '.'));
      const loadPoints = (task.quantityUnit === 'pallet' && !isNaN(qtyVal)) ? qtyVal : 1;
      totalLoad += loadPoints;

      if (task.quantityUnit === 'pallet') palCount += qtyVal;
      else pcsTasks++;

      if (task.isDone && task.completedBy) {
          let validatedTrips = 0;
          let oneWayD = 0;

          // 1. CHAINING LOGIC
          if (lastWorkplaceCoords && !task.isLogistics && task.pickedFromSectorId) {
              const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
              if (sector) {
                  const transitD = Math.sqrt(Math.pow(sector.coordX - lastWorkplaceCoords.x, 2) + Math.pow(sector.coordY - lastWorkplaceCoords.y, 2)) / 10;
                  totalTransitBetweenTasksDist += transitD;
              }
          }

          // 2. TASK DISTANCE
          if (task.isLogistics) {
              const logOp = logisticsOperations.find(o => o.value === task.workplace);
              if (logOp && logOp.distancePx) {
                  oneWayD = logOp.distancePx;
                  const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                  const possibleTrips = Math.round(( (durationMs / 1000) * VZV_SPEED_MPS ) / (2 * oneWayD));
                  validatedTrips = Math.min(Math.max(1, Math.floor(qtyVal)), Math.max(1, possibleTrips));
              }
          } else if (task.pickedFromSectorId && task.workplace) {
              const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
              const wp = workplaces.find(w => w.value === task.workplace);
              if (sector && wp) {
                  const dx = (wp.coordX || 0) - (sector.coordX || 0);
                  const dy = (wp.coordY || 0) - (sector.coordY || 0);
                  oneWayD = Math.sqrt(dx*dx + dy*dy) / 10;
                  const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                  const possibleTrips = Math.round(( (durationMs / 1000) * VZV_SPEED_MPS ) / (2 * oneWayD));
                  validatedTrips = Math.min(Math.max(1, Math.floor(qtyVal)), Math.max(1, possibleTrips));
                  lastWorkplaceCoords = { x: wp.coordX || 0, y: wp.coordY || 0 };
              }
          }

          if (validatedTrips > 0) {
              totalFullDist += validatedTrips * oneWayD;
              totalEmptyDist += (validatedTrips > 1 ? (validatedTrips - 1) * oneWayD : 0);
          }
      }

      // --- HLAVNÝ VÝPOČET ČASU A VÝKONU (CAP + ANTI-CHEAT) ---
      if (task.startedAt && task.completedAt) {
        const rawDurationMs = task.completedAt - task.startedAt;
        const blockedMs = calculateBlockedTime(task.inventoryHistory, task.startedAt, task.completedAt);
        const realDurationMs = Math.max(rawDurationMs - blockedMs, 0);

        // 1. Reálny čas práce pre displej dochádzky
        totalExecMs += realDurationMs;
        durations.push(realDurationMs);

        // 2. Vyhľadanie normy
        const norm = task.isLogistics 
            ? (logisticsOperations.find(o => o.value === task.workplace)?.standardTime || 0)
            : (workplaces.find(w => w.value === task.workplace)?.standardTime || 0);

        const targetMin = norm * qtyVal;
        const durationMin = realDurationMs / 60000;

        // 3. Adjusted Time Logic (Anti-Cheat & Floor)
        let adjustedMin;
        if (durationMin < 0.5) {
            // PENALTY: Úloha pod 30s -> berie sa ako 2x norma (Vždy 50%)
            adjustedMin = (targetMin * 2) || 2; 
        } else if (durationMin < 1) {
            // Safety Floor (Min 1 minúta)
            adjustedMin = 1;
        } else {
            // Reálny čistý čas
            adjustedMin = durationMin;
        }

        // 4. Per-task Performance s limitom 200%
        if (targetMin > 0) {
            const taskPerf = (targetMin / adjustedMin) * 100;
            const cappedPerf = Math.min(taskPerf, 200);
            sumPerformance += cappedPerf;
            countPerformanceTasks++;
            totalStandardMin += targetMin;
        }
      }

      if (task.createdAt && task.startedAt) {
        const react = task.startedAt - task.createdAt;
        if (react > 0) { totalReactionMs += react; reactionCount++; }
      }

      const isProd = (task.isProduction === true) || (!task.isLogistics && !!task.workplace);
      if (isProd && task.workplace) workplacesMap[task.workplace] = (workplacesMap[task.workplace] || 0) + 1;
      if (task.partNumber) partsMap[task.partNumber] = (partsMap[task.partNumber] || 0) + 1;

      if (task.isMissing) {
        missingReported++;
        if (task.auditResult === 'NOK') realErrors++;
      }
    });

    const numDays = Math.max(uniqueDaysWorked.size, 1);
    const SHIFT_MINUTES = 450;
    const totalAvailableMinutes = numDays * SHIFT_MINUTES;
    const pureWorkMinutes = totalExecMs / 60000;

    // WPI Score Logic
    const performanceRatio = countPerformanceTasks > 0 ? (sumPerformance / countPerformanceTasks) : 0;
    const avgReactionSeconds = reactionCount > 0 ? (totalReactionMs / reactionCount) / 1000 : 0;
    const confidenceRating = missingReported > 0 ? ((missingReported - realErrors) / missingReported) * 100 : 100;
    const grandTotalEmptyDist = totalEmptyDist + totalTransitBetweenTasksDist;
    const logEfficiency = (totalFullDist + grandTotalEmptyDist) > 0 ? (totalFullDist / (totalFullDist + grandTotalEmptyDist)) * 100 : 50;

    const utilizationPercent = (pureWorkMinutes * 1.15 / totalAvailableMinutes) * 100;

    const scoreQuality = (confidenceRating / 100) * 3.0;
    const scoreUtilization = (Math.min(utilizationPercent, 100) / 100) * 2.5;
    const scoreStandards = performanceRatio > 0 ? (Math.min(performanceRatio, 200) / 200) * 2.0 : 1.0; 
    const scoreReaction = avgReactionSeconds > 0 ? (avgReactionSeconds < 60 ? 1.0 : avgReactionSeconds < 180 ? 0.5 : 0) : 0.5;
    const scoreLogistics = (logEfficiency / 100) * 1.0;

    const workerIndex = parseFloat((scoreQuality + scoreUtilization + scoreStandards + scoreReaction + scoreLogistics).toFixed(1));

    return {
      totalLoad, palCount, pcsTasks, 
      confidenceRating, realErrors, missingReported,
      totalExecMs, 
      avgMsPerPoint: durations.length > 0 ? totalExecMs / totalLoad : 0,
      topWorkplaces: Object.entries(workplacesMap).sort(([,a],[,b]) => b-a).slice(0, 3).map(([name, count]) => ({ name, count })),
      topParts: Object.entries(partsMap).sort(([,a],[,b]) => b-a).slice(0, 3).map(([name, count]) => ({ name, count })),
      utilizationPercent, pureWorkMinutes, workerIndex, performanceRatio, avgReactionSeconds,
      totalFullDist, totalEmptyDist: grandTotalEmptyDist, transitOnlyDist: totalTransitBetweenTasksDist,
      logEfficiency, totalStandardMin
    };
  }, [tasks, systemBreaks, mapSectors, workplaces, systemConfig, VZV_SPEED_MPS, logisticsOperations]);

  const formatDuration = (ms: number) => {
    if (ms <= 0) return '-';
    const minutes = Math.round(ms / 60000);
    if (minutes < 1) return '< 1 min';
    if (minutes >= 60) return `${Math.floor(minutes / 60)}h ${minutes % 60}m`;
    return `${minutes} min`;
  };

  const formatMinutes = (totalMin: number) => {
